import app from 'flarum/forum/app';
import Component from 'flarum/common/Component';
import { dismissBanner } from '../utils/install-state';
export default class ApplePrompt extends Component {
  visible = false;
  arrowDir = 'down';
  orientationHandler = null;
  delayTimer = null;
  oninit(vnode) {
    super.oninit(vnode);
    const delay = app.forum.attribute('resofire-pwa.iosPromptDelay') ?? 10000;
    this.delayTimer = setTimeout(() => {
      this.visible = true;
      this.updateArrow();
      m.redraw();
    }, delay);
  }
  oncreate(vnode) {
    super.oncreate(vnode);
    this.orientationHandler = () => {
      this.updateArrow();
      m.redraw();
    };
    window.addEventListener('orientationchange', this.orientationHandler);
    window.addEventListener('resize', this.orientationHandler);
  }
  onremove() {
    if (this.delayTimer !== null) clearTimeout(this.delayTimer);
    if (this.orientationHandler) {
      window.removeEventListener('orientationchange', this.orientationHandler);
      window.removeEventListener('resize', this.orientationHandler);
    }
  }
  view() {
    if (!this.visible) return null;
    const appName = app.forum.attribute('resofire-pwa.appName') || app.forum.attribute('title') || '';
    const customText = app.forum.attribute('resofire-pwa.iosPromptText') || '';
    const promptText = customText ? customText.replace('{appName}', appName) : app.translator.trans('resofire-pwa.forum.apple.prompt_text', {
      appName
    });
    return m("div", {
      className: 'PWA-apple' + (this.arrowDir === 'up' ? ' PWA-apple--arrow-up' : ' PWA-apple--arrow-down')
    }, m("div", {
      className: "PWA-apple-body"
    }, m("div", {
      className: "PWA-apple-icon"
    }, m("i", {
      className: "fas fa-share-square"
    })), m("p", {
      className: "PWA-apple-text"
    }, promptText)), m("button", {
      className: "PWA-apple-dismiss",
      "aria-label": app.translator.trans('resofire-pwa.forum.apple.dismiss'),
      onclick: this.onDismiss.bind(this)
    }, m("i", {
      className: "fas fa-times"
    })), m("div", {
      className: 'PWA-apple-arrow PWA-apple-arrow--' + this.arrowDir
    }));
  }

  /**
   * Determine whether Safari's share button is at the top or bottom
   * of the screen for the current device and orientation.
   *
   * Rules:
   * - iPad: always top (iosPadAlwaysUp setting)
   * - iPhone portrait: share button is at the bottom toolbar → arrow down
   * - iPhone landscape: share button moves to the top → arrow up
   */
  updateArrow() {
    const isPad = /iPad/.test(navigator.userAgent) || /Macintosh/.test(navigator.userAgent) && navigator.maxTouchPoints > 1;
    const autoDetect = app.forum.attribute('resofire-pwa.iosAutoDetectOrientation') ?? true;
    const padAlwaysUp = app.forum.attribute('resofire-pwa.iosPadAlwaysUp') ?? true;
    if (isPad && padAlwaysUp) {
      this.arrowDir = 'up';
      return;
    }
    if (!autoDetect) {
      this.arrowDir = 'down';
      return;
    }

    // Portrait: window.innerHeight > window.innerWidth
    const isPortrait = window.innerHeight > window.innerWidth;
    this.arrowDir = isPortrait ? 'down' : 'up';
  }
  onDismiss() {
    this.visible = false;
    dismissBanner();
    this.attrs.onDismiss();
    m.redraw();
  }
}
flarum.reg.add('resofire-pwa', 'forum/components/ApplePrompt', ApplePrompt);