/**
 * Manages localStorage flags that track install prompt state.
 *
 * Keys:
 *   pwa.visited          — set on first page load
 *   pwa.banner.dismissed — set when user taps × on the banner (permanent)
 *   pwa.sheet.seen       — set when the bottom sheet has been shown once
 *   pwa.installed        — set when the user accepts the install prompt
 */

const VISITED = 'pwa.visited';
const BANNER_DISMISSED = 'pwa.banner.dismissed';
const SHEET_SEEN = 'pwa.sheet.seen';
const INSTALLED = 'pwa.installed';
function get(key) {
  try {
    return localStorage.getItem(key) === '1';
  } catch {
    return false;
  }
}
function set(key) {
  try {
    localStorage.setItem(key, '1');
  } catch {
    // localStorage unavailable — fail silently.
  }
}
export function isFirstVisit() {
  return !get(VISITED);
}
export function isSecondVisit() {
  return get(VISITED) && !get(SHEET_SEEN);
}
export function markVisited() {
  set(VISITED);
}
export function isBannerDismissed() {
  return get(BANNER_DISMISSED);
}
export function dismissBanner() {
  set(BANNER_DISMISSED);
}
export function isSheetSeen() {
  return get(SHEET_SEEN);
}
export function markSheetSeen() {
  set(SHEET_SEEN);
}
export function isInstalled() {
  return get(INSTALLED);
}
export function markInstalled() {
  set(INSTALLED);
}
export function isStandalone() {
  return window.matchMedia('(display-mode: standalone)').matches || !!navigator.standalone || document.referrer.startsWith('android-app://');
}
export function isIOS() {
  const ua = navigator.userAgent;
  // iPhone / iPod
  if (/iPad|iPhone|iPod/.test(ua)) return true;
  // iPadOS 13+ reports as Macintosh with touch support
  if (/Macintosh/.test(ua) && navigator.maxTouchPoints > 1) return true;
  return false;
}
export function isAndroid() {
  return /Android/.test(navigator.userAgent);
}
export function isMobile() {
  return isIOS() || isAndroid();
}
export function isSafari() {
  return /Safari/.test(navigator.userAgent) && !/Chrome|CriOS|FxiOS|EdgiOS/.test(navigator.userAgent);
}
flarum.reg.add('resofire-pwa', 'forum/utils/install-install-state', { isFirstVisit: isFirstVisit,isSecondVisit: isSecondVisit,markVisited: markVisited,isBannerDismissed: isBannerDismissed,dismissBanner: dismissBanner,isSheetSeen: isSheetSeen,markSheetSeen: markSheetSeen,isInstalled: isInstalled,markInstalled: markInstalled,isStandalone: isStandalone,isIOS: isIOS,isAndroid: isAndroid,isMobile: isMobile,isSafari: isSafari, });